--
-- Name: v_domain_statistics; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_domain_statistics AS
 SELECT gd.name AS domain,
    count(*) AS samples,
    round(avg(ar.value), 3) AS avg_au,
    min(ar.value) AS min_au,
    max(ar.value) AS max_au
   FROM (((public.assay_results ar
     JOIN public.samples s ON ((s.id = ar.sample_id)))
     JOIN public.domain_assignments da ON (((da.drillhole_id = s.drillhole_id) AND (s."interval" && da."interval"))))
     JOIN public.geological_domains gd ON ((gd.id = da.domain_id)))
  WHERE (ar.element_id = ( SELECT elements.id
           FROM public.elements
          WHERE (elements.symbol = 'Au'::text)))
  GROUP BY gd.name
  ORDER BY (round(avg(ar.value), 3)) DESC;


