--
-- Name: v_sample_geology; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_sample_geology AS
 SELECT s.id AS sample_id,
    s.drillhole_id,
    s."interval",
    dh.hole_id AS drillhole_name,
    l.code AS lithology,
    a.code AS alteration,
    mt.code AS mineralization,
    gd.name AS domain,
    ar.value AS au_grade
   FROM ((((((((((public.samples s
     JOIN public.drillholes dh ON ((dh.id = s.drillhole_id)))
     LEFT JOIN public.lithology_intervals li ON (((li.drillhole_id = s.drillhole_id) AND (s."interval" && li."interval"))))
     LEFT JOIN public.lithologies l ON ((l.id = li.lithology_id)))
     LEFT JOIN public.alteration_events ae ON (((ae.drillhole_id = s.drillhole_id) AND (s."interval" && ae."interval"))))
     LEFT JOIN public.alteration_types a ON ((a.id = ae.alteration_id)))
     LEFT JOIN public.mineralization_intervals mi ON (((mi.drillhole_id = s.drillhole_id) AND (s."interval" && mi."interval"))))
     LEFT JOIN public.mineralization_types mt ON ((mt.id = mi.mineralization_id)))
     LEFT JOIN public.domain_assignments da ON (((da.drillhole_id = s.drillhole_id) AND (s."interval" && da."interval"))))
     LEFT JOIN public.geological_domains gd ON ((gd.id = da.domain_id)))
     LEFT JOIN public.assay_results ar ON (((ar.sample_id = s.id) AND (ar.element_id = ( SELECT elements.id
           FROM public.elements
          WHERE (elements.symbol = 'Au'::text))))));


