--
-- Name: v_drillhole_summary _RETURN; Type: RULE; Schema: public; Owner: -
--

CREATE OR REPLACE VIEW public.v_drillhole_summary AS
 SELECT dh.id,
    dh.hole_id,
    dh.total_depth,
    count(s.id) AS n_samples,
    round(avg(ar.value), 3) AS avg_au,
    max(ar.value) AS max_au
   FROM ((public.drillholes dh
     LEFT JOIN public.samples s ON ((s.drillhole_id = dh.id)))
     LEFT JOIN public.assay_results ar ON (((ar.sample_id = s.id) AND (ar.element_id = ( SELECT elements.id
           FROM public.elements
          WHERE (elements.symbol = 'Au'::text))))))
  GROUP BY dh.id;


